import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

// Server metadata appears in the initialize handshake response
const server = new McpServer({
  name: "demo-server",
  version: "1.0.0",
});

// Register a tool - description is what Claude reads to decide when to call it
server.tool(
  "add_numbers",
  "Add two numbers and return their sum. Use when arithmetic is needed.",
  {
    a: z.number().describe("First operand"),
    b: z.number().describe("Second operand"),
  },
  async ({ a, b }) => ({
    content: [{ type: "text", text: String(a + b) }],
  })
);

// StdioServerTransport: stdin = requests in, stdout = responses out
// ALL diagnostic output must go to stderr - stdout is the message channel
const transport = new StdioServerTransport();
await server.connect(transport);
console.error("Server ready"); // stderr only - never console.log here

import express from "express";
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";

const app = express();
app.use(express.json());

// One transport (and server) per connected client
const sessions = new Map<string, SSEServerTransport>();

// Client opens a GET to /sse and receives a persistent event stream
app.get("/sse", async (req, res) => {
  const transport = new SSEServerTransport("/messages", res);
  const { sessionId } = transport;
  sessions.set(sessionId, transport);

  const server = new McpServer({ name: "remote-server", version: "1.0.0" });
  // Register tools here...

  res.on("close", () => {
    sessions.delete(sessionId);
  });

  await server.connect(transport);
});

// Client POSTs JSON-RPC requests to /messages?sessionId=...
app.post("/messages", async (req, res) => {
  const { sessionId } = req.query as { sessionId: string };
  const transport = sessions.get(sessionId);
  if (!transport) { res.status(404).json({ error: "Session not found" }); return; }
  await transport.handlePostMessage(req, res, req.body);
});

app.listen(3000);

