// Authentication middleware for HTTP/SSE MCP servers
import { Request, Response, NextFunction } from "express";
import crypto from "crypto";

function authenticateMCP(req: Request, res: Response, next: NextFunction) {
  const auth = req.headers.authorization;
  if (!auth?.startsWith("Bearer ")) {
    res.status(401).json({ error: "Missing Authorization header" });
    return;
  }
  const token = auth.slice(7);
  // Use constant-time comparison to prevent timing side-channel attacks
  const expected = Buffer.from(process.env.MCP_API_KEY!);
  const provided = Buffer.from(token);
  if (expected.length !== provided.length ||
      !crypto.timingSafeEqual(expected, provided)) {
    res.status(401).json({ error: "Invalid token" });
    return;
  }
  next();
}

// Apply auth before CORS middleware — preflight must pass auth too
app.use(authenticateMCP);

// Keepalive prevents proxy/load balancer from closing idle SSE connections
function setupKeepalive(res: express.Response, intervalMs = 25_000) {
  const timer = setInterval(() => {
    // SSE comment: starts with ":" — ignored by event parsers
    if (!res.writableEnded) {
      res.write(":keepalive\n\n");
    } else {
      clearInterval(timer);
    }
  }, intervalMs);
  res.on("close", () => clearInterval(timer));
}

// Client reconnection with exponential backoff
async function connectSSE(url: string, headers: Record<string, string>) {
  for (let attempt = 0; attempt < 10; attempt++) {
    try {
      const eventSource = new EventSource(url);
      return eventSource;
    } catch {
      const delay = Math.min(500 * 2 ** attempt, 30_000);
      await new Promise((r) => setTimeout(r, delay));
    }
  }
  throw new Error("Failed to connect after max retries");
}
